mapper.select:
SELECT CUSTCD, CUSTNM, BOSSNM AS USERNM, TELNO AS COMPANY_TEL, TELNO AS HPNO, ADDRESS, EMAIL, CUSTGBN, STATUS
FROM HABA020T_TBL
WHERE CMPYCD = #{CMPYCD} AND CUSTCD = #{CUSTCD}

SELECT A.START_TIME, C.CUSTNM, A.CALL_TELNO AS HPNO, A.CALL_USERNM, A.CALL_EMAIL, A.SVCNO, A.AI_SUMMARY, A.TRB_MENT, A.ANS_MENT, A.ESC_MEMO, U.USERNM AS CONSULTNM, A.CONSULTID, A.REC_FILE, A.CMPYCD FROM CALL_MST_TBL A LEFT JOIN HABA020T_TBL C ON A.CMPYCD = C.CMPYCD AND A.CUSTCD = C.CUSTCD LEFT JOIN HABA920T_TBL U ON A.CMPYCD = U.CMPYCD AND A.CONSULTID = U.USERID WHERE A.CMPYCD = #{CMPYCD, jdbcType=VARCHAR} AND A.SVCYMD BETWEEN #{FROMDT, jdbcType=VARCHAR} AND #{TODT, jdbcType=VARCHAR}
AND C.CUSTNM LIKE CONCAT('%', #{custnm, jdbcType=VARCHAR}, '%')
ORDER BY A.START_TIME DESC
